# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
from google.cloud import storage

def process_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    metadata = blob.metadata or {}
    
    base_name = os.path.splitext(file_name)[0]
    original_ext = os.path.splitext(file_name)[1]
    
    output_format = metadata.get('output_format', 'jpg')
    quality = metadata.get('quality', '85')
    resize = metadata.get('resize', '')
    rotate = metadata.get('rotate', '')
    grayscale = metadata.get('grayscale', 'false')
    blur = metadata.get('blur', '')
    sharpen = metadata.get('sharpen', '')
    brightness_contrast = metadata.get('brightness_contrast', '')
    crop = metadata.get('crop', '')
    flip = metadata.get('flip', '')
    flop = metadata.get('flop', '')
    normalize = metadata.get('normalize', 'false')
    auto_orient = metadata.get('auto_orient', 'true')
    strip = metadata.get('strip', 'true')
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'processed/')
    
    tmp_input_path = f'/tmp/input_{os.path.basename(file_name)}'
    output_file_name = f'{base_name}.{output_format}'
    tmp_output_path = f'/tmp/output_{os.path.basename(output_file_name)}'
    
    blob.download_to_filename(tmp_input_path)
    
    convert_command = ['convert', tmp_input_path]
    
    if auto_orient.lower() == 'true':
        convert_command.extend(['-auto-orient'])
    
    if strip.lower() == 'true':
        convert_command.extend(['-strip'])
    
    if resize:
        convert_command.extend(['-resize', resize])
    
    if rotate:
        convert_command.extend(['-rotate', rotate])
    
    if crop:
        convert_command.extend(['-crop', crop])
    
    if grayscale.lower() == 'true':
        convert_command.extend(['-colorspace', 'Gray'])
    
    if blur:
        convert_command.extend(['-blur', blur])
    
    if sharpen:
        convert_command.extend(['-sharpen', sharpen])
    
    if brightness_contrast:
        convert_command.extend(['-brightness-contrast', brightness_contrast])
    
    if flip.lower() == 'true':
        convert_command.extend(['-flip'])
    
    if flop.lower() == 'true':
        convert_command.extend(['-flop'])
    
    if normalize.lower() == 'true':
        convert_command.extend(['-normalize'])
    
    convert_command.extend(['-quality', quality])
    
    convert_command.append(tmp_output_path)
    
    result = subprocess.call(convert_command)
    
    if result != 0:
        raise Exception(f'ImageMagick conversion failed with exit code {result}')
    
    output_blob_name = f'{output_prefix}{output_file_name}'
    output_bucket_obj = storage_client.bucket(output_bucket)
    output_blob = output_bucket_obj.blob(output_blob_name)
    
    output_blob.upload_from_filename(tmp_output_path)
    
    os.remove(tmp_input_path)
    os.remove(tmp_output_path)
    
    print(f'Successfully processed {file_name} to {output_bucket}/{output_blob_name}')
    print(f'Conversion options used: format={output_format}, quality={quality}, resize={resize}')